#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-17

# ============================================================================
# Prompt Cache Safety Tests
# ============================================================================
# Validates that skills and agents follow prompt caching rules from
# CONTRIBUTING-SKILLS.md. Catches cache-busting regressions before they ship.
#
# Tests:
# 1. No skill dynamically changes allowed-tools mid-session
# 2. Agent prompts have stable content before variable content
# 3. No model changes suggested in skill instructions
# 4. No MCP server additions in skill body (only frontmatter)
#
# Usage: ./test-cache-safety.sh [--verbose]
# Exit codes: 0 = all pass, 1 = failures found
# ============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../../.." && pwd)}"
SKILLS_DIR="$PROJECT_ROOT/src/skills"
AGENTS_DIR="$PROJECT_ROOT/src/agents"

VERBOSE="${1:-}"

# Counters
PASS_COUNT=0
FAIL_COUNT=0
WARN_COUNT=0

# Colors (only if stdout is a terminal)
if [[ -t 1 ]]; then
    RED='\033[0;31m'
    GREEN='\033[0;32m'
    YELLOW='\033[1;33m'
    NC='\033[0m'
else
    RED='' GREEN='' YELLOW='' NC=''
fi

pass() { ((PASS_COUNT++)); echo -e "  ${GREEN}PASS${NC}: $1"; }
fail() { ((FAIL_COUNT++)); echo -e "  ${RED}FAIL${NC}: $1"; }
warn() { ((WARN_COUNT++)); echo -e "  ${YELLOW}WARN${NC}: $1"; }

echo "============================================================================"
echo "  Prompt Cache Safety Tests"
echo "============================================================================"
echo ""

# ── Test 1: No dynamic allowed-tools changes in skill body ──────────────
echo "▶ Test 1: No dynamic allowed-tools changes in skill body"
echo "────────────────────────────────────────"

DYNAMIC_TOOLS_FOUND=0
while IFS= read -r skill_dir; do
    skill_name=$(basename "$skill_dir")
    skill_file="$skill_dir/SKILL.md"
    [[ -f "$skill_file" ]] || continue

    # Check skill body (after frontmatter) for patterns that modify tools
    body=$(awk '/^---$/{n++; next} n>=2' "$skill_file" || true)

    if echo "$body" | grep -qiE '(change|modify|update|add|remove).*(allowed.?tools|tool.?list)' 2>/dev/null; then
        fail "$skill_name: body suggests modifying allowed-tools mid-session"
        DYNAMIC_TOOLS_FOUND=1
        if [[ "$VERBOSE" == "--verbose" ]]; then
            echo "    $(echo "$body" | grep -iE '(change|modify|update|add|remove).*(allowed.?tools|tool.?list)' | head -1 || true)"
        fi
    fi
done < <(find "$SKILLS_DIR" -mindepth 1 -maxdepth 1 -type d | sort)

if [[ $DYNAMIC_TOOLS_FOUND -eq 0 ]]; then
    pass "No skills dynamically change allowed-tools"
fi

# ── Test 2: Agent prompts have stable prefix ────────────────────────────
echo ""
echo "▶ Test 2: Agent prompt structure (stable before variable)"
echo "────────────────────────────────────────"

UNSTABLE_AGENTS=0
while IFS= read -r agent_file; do
    agent_name=$(basename "$agent_file" .md)

    # Check if agent starts with variable/dynamic content before stable instructions
    # Pattern: first non-frontmatter line starts with a variable reference like ${} or $ARGUMENTS
    body=$(awk '/^---$/{n++; next} n>=2' "$agent_file" || true)
    first_line=$(echo "$body" | grep -v '^$' | head -1 || true)

    if echo "$first_line" | grep -qE '^\$\{|^\$[A-Z]|^\{\{' 2>/dev/null; then
        warn "$agent_name: first content line starts with variable (may bust cache)"
        UNSTABLE_AGENTS=1
    fi
done < <(find "$AGENTS_DIR" -name "*.md" -type f | sort)

if [[ $UNSTABLE_AGENTS -eq 0 ]]; then
    pass "All agent prompts have stable content prefix"
fi

# ── Test 3: No model changes in skill body ──────────────────────────────
echo ""
echo "▶ Test 3: No model changes suggested in skill instructions"
echo "────────────────────────────────────────"

MODEL_CHANGE_FOUND=0
while IFS= read -r skill_dir; do
    skill_name=$(basename "$skill_dir")
    skill_file="$skill_dir/SKILL.md"
    [[ -f "$skill_file" ]] || continue

    body=$(awk '/^---$/{n++; next} n>=2' "$skill_file" || true)

    # Check for instructions to change model mid-session
    if echo "$body" | grep -qiE '(switch|change|set).*(model|to opus|to sonnet|to haiku).*mid.?session'; then
        fail "$skill_name: suggests changing model mid-session (busts cache)"
        MODEL_CHANGE_FOUND=1
    fi
done < <(find "$SKILLS_DIR" -mindepth 1 -maxdepth 1 -type d | sort)

if [[ $MODEL_CHANGE_FOUND -eq 0 ]]; then
    pass "No skills suggest mid-session model changes"
fi

# ── Test 4: No MCP server additions in skill body ───────────────────────
echo ""
echo "▶ Test 4: No MCP server additions in skill body"
echo "────────────────────────────────────────"

MCP_BODY_FOUND=0
while IFS= read -r skill_dir; do
    skill_name=$(basename "$skill_dir")
    skill_file="$skill_dir/SKILL.md"
    [[ -f "$skill_file" ]] || continue

    body=$(awk '/^---$/{n++; next} n>=2' "$skill_file" || true)

    # Check for instructions to add MCP servers in body (should be frontmatter only)
    if echo "$body" | grep -qiE '(add|install|configure|connect).*(mcp.?server|MCP server)' 2>/dev/null; then
        # Exclude documentation/reference patterns
        match=$(echo "$body" | grep -iE '(add|install|configure|connect).*(mcp.?server|MCP server)' | head -1 || true)
        if ! echo "$match" | grep -qiE '(see|refer|documented|frontmatter|example|affects|unaffected|sourced|profile|persist)' 2>/dev/null; then
            fail "$skill_name: body instructs adding MCP servers (should be frontmatter)"
            MCP_BODY_FOUND=1
        fi
    fi
done < <(find "$SKILLS_DIR" -mindepth 1 -maxdepth 1 -type d | sort)

if [[ $MCP_BODY_FOUND -eq 0 ]]; then
    pass "No skills add MCP servers in body (frontmatter only)"
fi

# ── Summary ──────────────────────────────────────────────────────────────
echo ""
echo "============================================================================"
echo ""
echo "  Total:    $((PASS_COUNT + FAIL_COUNT + WARN_COUNT))"
echo "  Passed:   ${GREEN}${PASS_COUNT}${NC}"
echo "  Failed:   ${RED}${FAIL_COUNT}${NC}"
echo "  Warnings: ${YELLOW}${WARN_COUNT}${NC}"
echo ""
echo "============================================================================"

if [[ $FAIL_COUNT -gt 0 ]]; then
    echo -e "  ${RED}FAILURES DETECTED${NC} — Fix cache-busting patterns before shipping"
    echo "============================================================================"
    exit 1
fi

echo -e "  ${GREEN}All cache safety tests passed${NC}"
echo "============================================================================"
exit 0
